$entry->setFieldValues(['body'=>'Pedro Fages y Beleta was born around 1734 in Guissona, Catalonia, Spain. He served as a lieutenant in the Catalonian Volunteers under Governor Gaspar de Portolá during the landmark 1769 expedition from San Diego to Monterey — the first European overland journey through the Santa Clarita Valley. Following the expedition, Fages was appointed commanding officer of the Presidio of San Diego before assuming command as governor of Alta California in 1770. In the spring of 1772, six of his soldados de cuero deserted with six Tataviam women, prompting Fages to lead a pursuit expedition that took him through the Santa Clara River Valley. He named Agua Dulce for its sweet water springs, camped at the confluence of Castaic Creek and the Santa Clara River, and ascended Castaic Canyon before crossing what he called Cañada de las Uvas — now Tejon Pass — into the San Joaquin Valley. He never found the deserters. His detailed account of the expedition added thousands of acres to previously blank maps of Alta California. Fages served as governor of Alta California from 1782 to 1791. He retired either to Mexico or to his family estate in Seville — accounts differ. He died in 1796.','fullName'=>'Pedro Fages','birthDate'=>'c. 1734','birthplace'=>'Guissona, Catalonia, Spain','deathDate'=>'1796','burialPlace'=>'','occupation'=>'Military Officer; Colonial Governor','authorBio'=>'Pedro Fages (c. 1734–1796) was a Catalonian soldier who served as military commander and governor of Alta California. He participated in the Portolá expedition of 1769 and in 1772 led an expedition through the Santa Clarita Valley in pursuit of deserters, naming several landmarks still in use today including Agua Dulce and Soledad.','personLegacyUrl'=>'','personGraveUrl'=>'','personWikipediaUrl'=>'','historicalEra'=>$eraIds,'historicalPeriod'=>$periodIds,'neighborhood'=>$hoodIds,'featuredImage'=>$featuredImageIds]);
if(Craft::$app->getElements()->saveElement($entry)){echo "Saved: Pedro Fages\n";}else{echo "FAILED: Pedro Fages - ".json_encode($entry->getErrors())."\n";}
